queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?science_fiction_book a :Science_Fiction_Book .
    ?science_fiction_book p:Title ?title .
    ?science_fiction_book p:Year_of_publication ?year_of_publication_f .
    FILTER((STR(?year_of_publication_f) = "2018" || STR(?year_of_publication_f) = "2018.0"))
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?romance_book a :Romance_Book .
    ?romance_book p:Title ?title .
    ?romance_book p:Year_of_publication ?year_of_publication_f .
    FILTER((STR(?year_of_publication_f) = "2018" || STR(?year_of_publication_f) = "2018.0"))
    BIND(?title AS ?o0)
  }
}

